import{_ as p,C as r,o as s,c as l,a5 as n,b as i,w as e,a as o,E as d,a4 as E}from"./chunks/framework.gGRxziV4.js";const C=JSON.parse('{"title":"评分器体系","description":"","frontmatter":{},"headers":[],"relativePath":"06-Agent评估/02-评分器体系.md","filePath":"06-Agent评估/02-评分器体系.md","lastUpdated":1774181700000}'),c={name:"06-Agent评估/02-评分器体系.md"};function b(u,a,h,A,B,m){const t=r("Mermaid");return s(),l("div",null,[a[1]||(a[1]=n(`<h1 id="评分器体系" tabindex="-1">评分器体系 <a class="header-anchor" href="#评分器体系" aria-label="Permalink to &quot;评分器体系&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 6 模块的第 2 章。</p></blockquote><p>代码、模型、人类——三种评分器的三角闭环。评估不是一次性工作，而是持续改进的循环。</p><hr><h2 id="三种评分器" tabindex="-1">三种评分器 <a class="header-anchor" href="#三种评分器" aria-label="Permalink to &quot;三种评分器&quot;">​</a></h2><h3 id="代码评分器" tabindex="-1">代码评分器 <a class="header-anchor" href="#代码评分器" aria-label="Permalink to &quot;代码评分器&quot;">​</a></h3><p>用代码判断输出是否满足条件。最快、最便宜、最一致。</p><p>典型实现：检查输出是否包含特定关键词、JSON 格式是否正确、代码是否能编译通过、测试是否全部 Pass。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>def grade_code(output):</span></span>
<span class="line"><span>    try:</span></span>
<span class="line"><span>        compile(output, &#39;&lt;string&gt;&#39;, &#39;exec&#39;)</span></span>
<span class="line"><span>        return {&quot;pass&quot;: True, &quot;score&quot;: 1.0}</span></span>
<span class="line"><span>    except SyntaxError as e:</span></span>
<span class="line"><span>        return {&quot;pass&quot;: False, &quot;score&quot;: 0.0, &quot;reason&quot;: str(e)}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>优势</strong>：确定性——同样的输入永远给出同样的分数。速度快——毫秒级。成本低——不需要额外 LLM 调用。</p><p><strong>劣势</strong>：只能判断能用代码表达的条件。不能判断创造性、语义正确性、风格。</p><h3 id="模型评分器" tabindex="-1">模型评分器 <a class="header-anchor" href="#模型评分器" aria-label="Permalink to &quot;模型评分器&quot;">​</a></h3><p>用 LLM 判断输出质量。比代码灵活，能评估语义层面。</p><p>典型实现：把原始问题、Agent 输出、评估标准一起喂给评分模型，让评分模型打分并给出理由。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>评估提示词：</span></span>
<span class="line"><span>问题：{query}</span></span>
<span class="line"><span>回答：{output}</span></span>
<span class="line"><span>评分标准：</span></span>
<span class="line"><span>- 准确性（0-4）：回答是否包含事实错误</span></span>
<span class="line"><span>- 完整性（0-4）：是否覆盖所有要求的方面</span></span>
<span class="line"><span>- 清晰度（0-4）：表达是否清楚易懂</span></span>
<span class="line"><span>请给出各项分数和总分，以及改进建议。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>优势</strong>：灵活——能评估语义、逻辑、风格等软性指标。可解释——评分模型能给出打分理由。</p><p><strong>劣势</strong>：不一致——同样的输出评两次可能分数不同。成本高——每次评分都需要 LLM 调用。有偏见——评分模型本身可能有系统性偏好。</p><h3 id="人类评分器" tabindex="-1">人类评分器 <a class="header-anchor" href="#人类评分器" aria-label="Permalink to &quot;人类评分器&quot;">​</a></h3><p>人类判断输出质量。最准确但最贵最慢。</p><p><strong>适用场景</strong>：高价值输出的最终验收、评分器校准（用人类评分来验证代码和模型评分器的准确性）、边界案例（自动化评分器判断不了的情况）。</p><hr><h2 id="评估金字塔" tabindex="-1">评估金字塔 <a class="header-anchor" href="#评估金字塔" aria-label="Permalink to &quot;评估金字塔&quot;">​</a></h2>`,22)),(s(),i(E,null,{default:e(()=>[d(t,{id:"mermaid-60",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E5%BA%95%E5%B1%82%3A%20%E4%BB%A3%E7%A0%81%E8%AF%84%E5%88%86%E5%99%A8%3Cbr%2F%3E%E8%A6%86%E7%9B%9680%25%20%E5%9C%BA%E6%99%AF%3Cbr%2F%3E%E6%A0%BC%E5%BC%8F%2F%E8%AF%AD%E6%B3%95%2F%E6%B5%8B%E8%AF%95%3Cbr%2F%3E%E6%AF%AB%E7%A7%92%E7%BA%A7%20%E8%BF%91%E9%9B%B6%E6%88%90%E6%9C%AC%5D%20--%3E%20B%5B%E4%B8%AD%E5%B1%82%3A%20%E6%A8%A1%E5%9E%8B%E8%AF%84%E5%88%86%E5%99%A8%3Cbr%2F%3E%E8%A6%86%E7%9B%9615%25%20%E5%9C%BA%E6%99%AF%3Cbr%2F%3E%E8%AF%AD%E4%B9%89%2F%E9%80%BB%E8%BE%91%2F%E8%B4%A8%E9%87%8F%3Cbr%2F%3E%E7%A7%92%E7%BA%A7%20%E4%B8%AD%E7%AD%89%E6%88%90%E6%9C%AC%5D%0A%20%20%20%20B%20--%3E%20C%5B%E9%A1%B6%E5%B1%82%3A%20%E4%BA%BA%E7%B1%BB%E8%AF%84%E5%88%86%E5%99%A8%3Cbr%2F%3E%E8%A6%86%E7%9B%965%25%20%E5%9C%BA%E6%99%AF%3Cbr%2F%3E%E6%9C%80%E7%BB%88%E9%AA%8C%E6%94%B6%2F%E8%BE%B9%E7%95%8C%3Cbr%2F%3E%E5%88%86%E9%92%9F%E7%BA%A7%20%E9%AB%98%E6%88%90%E6%9C%AC%5D%0A%20%20%20%20D%5B%E5%85%A8%E9%83%A8%E8%BE%93%E5%87%BA%5D%20--%3E%20A%0A%20%20%20%20A%20--%3E%7C%E9%80%9A%E8%BF%87%7C%20E%5B%E6%8A%BD%E6%A0%B710-20%25%5D%0A%20%20%20%20E%20--%3E%20B%0A%20%20%20%20B%20--%3E%7C%E5%85%B3%E9%94%AE%E8%8A%82%E7%82%B9%7C%20F%5B%E9%AB%98%E4%BB%B7%E5%80%BC%E8%BE%93%E5%87%BA%5D%0A%20%20%20%20F%20--%3E%20C%0A%20%20%20%20style%20A%20fill%3A%234a9%0A%20%20%20%20style%20B%20fill%3A%238cf%0A%20%20%20%20style%20C%20fill%3A%23f96%0A"})]),fallback:e(()=>[...a[0]||(a[0]=[o(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=n(`<blockquote><p>💡 <strong>图解：</strong> 80% 的评估用代码自动完成、15% 用模型语义检查、5% 留给人类——能用代码就不用模型，能用模型就不用人。</p></blockquote><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>          /\\</span></span>
<span class="line"><span>         /人\\        ← 少量、高价值、高成本</span></span>
<span class="line"><span>        /模型\\       ← 中量、中价值、中成本</span></span>
<span class="line"><span>       /代码 \\      ← 大量、低成本、自动化</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>底层：代码评分器</strong>——覆盖 80% 的评估场景。格式检查、语法验证、测试执行。每个输出都过一遍。</p><p><strong>中层：模型评分器</strong>——覆盖 15% 的评估场景。语义正确性、逻辑完整性、回答质量。对代码评分器通过的输出做进一步评估。</p><p><strong>顶层：人类评分器</strong>——覆盖 5% 的评估场景。最终验收、边界案例、评分器校准。只在关键节点使用。</p><p>80% 的评估用代码评分器自动化完成，15% 用模型评分器做语义检查，5% 留给人类做最终判断。</p><hr><h2 id="评分器的校准" tabindex="-1">评分器的校准 <a class="header-anchor" href="#评分器的校准" aria-label="Permalink to &quot;评分器的校准&quot;">​</a></h2><p>评分器本身也可能出错。需要定期校准——用人类评估结果来验证自动化评分器的准确性。</p><p>校准方法：随机抽样一批输出，同时用自动化评分器和人类评分。比较两者的打分一致性（Kappa 系数）。如果一致性低于阈值，需要调整评分器。</p><p>模型评分器尤其需要校准——不同版本的评分模型可能有不同的评分标准。定期用人类评分来锚定。</p><hr><h2 id="评分器的选择" tabindex="-1">评分器的选择 <a class="header-anchor" href="#评分器的选择" aria-label="Permalink to &quot;评分器的选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>代码评分器</th><th>模型评分器</th><th>人类评分器</th></tr></thead><tbody><tr><td>速度</td><td>毫秒级</td><td>秒级</td><td>分钟-小时级</td></tr><tr><td>成本</td><td>近零</td><td>中等</td><td>高</td></tr><tr><td>一致性</td><td>100%</td><td>80-95%</td><td>70-90%</td></tr><tr><td>灵活性</td><td>低</td><td>中</td><td>高</td></tr><tr><td>适用</td><td>格式/语法/测试</td><td>语义/逻辑/质量</td><td>最终验收/边界</td></tr></tbody></table><p>选择原则：能用代码判断的就不用模型，能用模型判断的就不用人。从最简单最快最便宜的评分器开始。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>三种评分器：代码（快便宜确定）、模型（灵活可解释）、人类（准确但贵慢）</li><li>评估金字塔：80% 代码 + 15% 模型 + 5% 人类</li><li>评分器需要校准：用人类评估验证自动化评分器准确性</li><li>选择原则：能用代码就不用模型，能用模型就不用人</li></ul><hr><p><strong>上一章</strong>: <a href="./01-为什么需要评估.html">为什么需要评估</a> | <strong>下一章</strong>: <a href="./03-四类评估与纵深防御.html">四类评估与纵深防御</a></p>`,20))])}const _=p(c,[["render",b]]);export{C as __pageData,_ as default};
